function getCookie(cname) {
    let name = cname + "=";
    let decodedCookie = decodeURIComponent(document.cookie);
    let ca = decodedCookie.split(";");
    for(let i = 0; i <ca.length; i++) {
    let c = ca[i];
    while (c.charAt(0) === " ") {
    c = c.substring(1);
    }
    if (c.indexOf(name) === 0) {
    return c.substring(name.length, c.length);
    }
    }
    return "";
}
function consentState() {
    const optanonCookieBoxClosedCookieValue = getCookie("OptanonAlertBoxClosed");

    if (!optanonCookieBoxClosedCookieValue) return "pending";

    const optanonConsentCookieValue = getCookie("OptanonConsent");

    if (optanonConsentCookieValue?.includes("C0002:1")) return "accepted";

    return "refused";
}

window.optimizely = window.optimizely || [];

switch(consentState()) {
    case "accepted":
        window.optimizely.push({
            type: "sendEvents",
        });
     break;
     case "refused":
        window.optimizely.push({
            type: "disable",
            scope: "tracking",
        });
    break; 
    case "pending":
        window.optimizely.push({
            type: "holdEvents",
        });
    break;
}

