const copyButton = jQuery(".copy-button")
jQuery(document).ready(function () {
	copyButton.click(function () {
		const button = jQuery(this);
		// Remove the content of the span tag inside the anchor
		const textToCopy = button.clone().children().remove().end().text().trim();;
		navigator.clipboard.writeText(textToCopy).then(function () {
			button.addClass("copied");
		}).catch(function (error) {
			console.error("Error copying text:");
		})
	});
	// Event listener for clicks outside of the copyButton
	jQuery(document).on('click', function (event) {
		if (!copyButton.is(event.target) && !copyButton.has(event.target).length) {
			copyButton.removeClass('copied');
		}
	});
});

